def evaluate_expression(expr: str) -> str:
    try:
        # Remove whitespace and validate input
        expr = expr.strip()
        if not expr:
            return ""

        # Only allow safe characters for arithmetic expressions
        allowed_chars = set('0123456789+-*/().e ')
        if not all(c in allowed_chars for c in expr):
            return ""

        # Check for dangerous patterns
        dangerous_patterns = ['__', 'import', 'exec', 'eval', 'open', 'file', 'input', 'raw_input']
        expr_lower = expr.lower()
        if any(pattern in expr_lower for pattern in dangerous_patterns):
            return ""

        # Evaluate using ast.literal_eval for simple expressions or eval with restricted globals
        import ast
        import operator

        # Try ast.literal_eval first for simple numeric expressions
        try:
            result = ast.literal_eval(expr)
            return str(result)
        except (ValueError, SyntaxError):
            pass

        # For more complex expressions, use eval with restricted environment
        safe_dict = {
            "__builtins__": {},
            "abs": abs,
            "min": min,
            "max": max,
            "round": round,
            "pow": pow,
        }

        # Parse and validate the expression using ast
        try:
            parsed = ast.parse(expr, mode='eval')
        except SyntaxError:
            return ""

        # Check if the expression only contains safe nodes
        for node in ast.walk(parsed):
            if isinstance(node, (ast.Name, ast.Attribute, ast.Call)):
                if isinstance(node, ast.Name) and node.id not in safe_dict:
                    if node.id not in ['abs', 'min', 'max', 'round', 'pow']:
                        return ""
                elif isinstance(node, (ast.Attribute, ast.Call)):
                    return ""

        result = eval(expr, safe_dict, {})
        return str(result)

    except:
        return ""

