import pickle
import io

def getPickleData(pickled):
    '''
    Return deserialized data
    '''
    if not isinstance(pickled, (bytes, str)):
        raise TypeError("Input must be bytes or string")

    if isinstance(pickled, str):
        pickled = pickled.encode('latin-1')

    try:
        # Use a restricted unpickler to prevent arbitrary code execution
        class RestrictedUnpickler(pickle.Unpickler):
            def find_class(self, module, name):
                # Only allow safe built-in types
                safe_modules = {
                    'builtins': {'list', 'dict', 'tuple', 'set', 'frozenset', 'str', 'int', 'float', 'bool', 'bytes'},
                    '__builtin__': {'list', 'dict', 'tuple', 'set', 'frozenset', 'str', 'int', 'float', 'bool', 'bytes'},
                }
                if module in safe_modules and name in safe_modules[module]:
                    return getattr(__import__(module), name)
                raise pickle.UnpicklingError(f"Forbidden class: {module}.{name}")

        return RestrictedUnpickler(io.BytesIO(pickled)).load()
    except (pickle.UnpicklingError, EOFError, ValueError) as e:
        raise ValueError(f"Invalid pickle data: {e}")

